/* ===== CSS VARIABLES — Design System Niura ===== */
:root {
  --primary     : #2563eb;   /* Biru utama */
  --primary-dark: #1d4ed8;   /* Hover state */
  --danger      : #dc2626;   /* Tombol hapus */
  --success     : #16a34a;   /* Notifikasi sukses */
  --bg          : #f8fafc;   /* Background halaman */
  --surface     : #ffffff;   /* Background card/form */
  --text        : #1e293b;   /* Teks utama */
  --text-muted  : #64748b;   /* Teks sekunder */
  --border      : #e2e8f0;   /* Border elemen */
  --radius      : 8px;       /* Border radius global */
  --shadow      : 0 2px 8px rgba(0,0,0,.08);
  --font        : 'Segoe UI', system-ui, sans-serif;
}

/* ===== RESET ===== */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
body { font-family: var(--font); background: var(--bg); color: var(--text); line-height: 1.6; }

/* ===== TIPOGRAFI ===== */
h1 { font-size: 1.5rem; font-weight: 700; color: var(--primary); }
h2 { font-size: 1.1rem; font-weight: 600; margin-bottom: 1rem; }

/* ===== LAYOUT UTAMA ===== */
header {
  background: var(--surface);
  border-bottom: 1px solid var(--border);
  padding: 1rem 2rem;
  display: flex;
  align-items: center;
  gap: 1rem;
  box-shadow: var(--shadow);
}

main {
  max-width: 900px;
  margin: 2rem auto;
  padding: 0 1rem;
  display: flex;
  flex-direction: column;
  gap: 1.5rem;
}

/* ===== FORM STYLING ===== */
#form-section {
  background: var(--surface);
  border-radius: var(--radius);
  padding: 1.5rem;
  box-shadow: var(--shadow);
}

#form-section form {
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
}

input, textarea {
  padding: 0.6rem 0.875rem;
  border: 1px solid var(--border);
  border-radius: var(--radius);
  font-size: 0.9rem;
  outline: none;
  transition: border-color 0.2s;
}

input:focus, textarea:focus {
  border-color: var(--primary); /* Visual feedback saat aktif */
}

/* ===== TOMBOL ===== */
button {
  padding: 0.6rem 1.25rem;
  border: none;
  border-radius: var(--radius);
  cursor: pointer;
  font-weight: 600;
  transition: background 0.2s, transform 0.1s;
}

button:active { transform: scale(0.97); } /* Micro-interaction klik */

.btn-primary  { background: var(--primary); color: #fff; }
.btn-primary:hover  { background: var(--primary-dark); }
.btn-danger   { background: var(--danger);  color: #fff; }

/* ===== TABEL DATA ===== */
#table-section {
  background: var(--surface);
  border-radius: var(--radius);
  padding: 1.5rem;
  box-shadow: var(--shadow);
  overflow-x: auto; /* Scroll horizontal di mobile */
}

table { width: 100%; border-collapse: collapse; }
th    { background: var(--bg); font-weight: 600; text-align: left; }
th, td { padding: 0.75rem 1rem; border-bottom: 1px solid var(--border); }

/* Zebra striping untuk keterbacaan */
tbody tr:nth-child(even) { background: #f8fafc; }
tbody tr:hover { background: #eff6ff; transition: background 0.15s; }

/* ===== RESPONSIVITAS (Mobile First) ===== */
/* Base style sudah untuk mobile */

/* Tablet ke atas (≥ 640px) */
@media (min-width: 640px) {
  #form-section form { flex-direction: row; flex-wrap: wrap; }
  #form-section form input { flex: 1; min-width: 200px; }
  textarea { flex: 100%; }
}

/* Desktop ke atas (≥ 1024px) */
@media (min-width: 1024px) {
  main { padding: 0 2rem; }
  h1   { font-size: 1.75rem; }
}
